// Target keywords for TotalGuard Yard Care — Madison, WI
// These are the top 20 keywords we track daily for rank movement.
const keywords = [
  'lawn care madison wi',
  'lawn mowing madison',
  'fertilization service madison',
  'lawn fertilization madison wi',
  'weed control madison wi',
  'aeration and overseeding madison',
  'lawn aeration madison wi',
  'spring lawn care madison',
  'fall lawn care madison',
  'organic lawn care madison wi',
  'yard maintenance madison wi',
  'grass cutting service madison',
  'lawn treatment madison wi',
  'lawn care near me madison',
  'best lawn care madison wi',
  'affordable lawn care madison',
  'commercial lawn care madison wi',
  'lawn care service dane county',
  'lawn mowing service near me',
  'totalguard yard care'
];

// Use yesterday as the sync date (GSC data has ~2 day lag,
// but TG-96 already synced the latest available date at 6am)
const syncDate = new Date(Date.now() - 2 * 24 * 60 * 60 * 1000)
  .toISOString().split('T')[0];

return [{ json: { keywords, syncDate } }];

// Match target keywords against GSC data and build seo_rankings rows
const keywords = $('Define Target Keywords').first().json.keywords;
const syncDate = $('Define Target Keywords').first().json.syncDate;
const gscRows = $input.first().json || [];

// Build lookup map from GSC data (query -> row)
const gscMap = new Map();
const dataArray = Array.isArray(gscRows) ? gscRows : (gscRows.body || []);
for (const row of dataArray) {
  if (row.query) {
    gscMap.set(row.query.toLowerCase(), row);
  }
}

const rankings = keywords.map(kw => {
  const match = gscMap.get(kw.toLowerCase());
  return {
    keyword: kw,
    position: match ? Math.round(match.position * 100) / 100 : null,
    clicks: match ? (match.clicks || 0) : 0,
    impressions: match ? (match.impressions || 0) : 0,
    date: syncDate
  };
});

// Filter to only keywords that have GSC data (position != null)
const withData = rankings.filter(r => r.position !== null);
const withoutData = rankings.filter(r => r.position === null);

return [{ json: {
  upsertData: withData,
  trackedCount: withData.length,
  missingCount: withoutData.length,
  missingKeywords: withoutData.map(r => r.keyword),
  syncDate
}}];
